"use client";

/**
 * MetricCards Component
 *
 * A row of KPI cards for dashboard overviews.
 * Optimized for Product Mode with minimal visual noise and data density.
 *
 * @example
 * ```tsx
 * <MetricCards
 *   metrics={[
 *     { label: 'Revenue', value: '$12,345', change: { value: '+12%', positive: true } },
 *     { label: 'Users', value: '1,234', change: { value: '+5%', positive: true } },
 *     { label: 'Conversion', value: '3.2%', change: { value: '-0.5%', positive: false } }
 *   ]}
 *   columns={3}
 * />
 * ```
 */

import { forwardRef } from "react";
import { TrendingUp, TrendingDown } from "lucide-react";
import type { MetricCardsProps, MetricCardProps } from "./MetricCards.types";
import styles from "./MetricCards.module.css";

// Sparkline mini component
const Sparkline = ({ data }: { data: number[] }) => {
  if (!data || data.length < 2) return null;

  const max = Math.max(...data);
  const min = Math.min(...data);
  const range = max - min || 1;
  const firstValue = data[0];
  const lastValue = data[data.length - 1];
  const height = 24;
  const width = 64;
  const stepX = width / (data.length - 1);

  const points = data
    .map((value, index) => {
      const x = index * stepX;
      const y = height - ((value - min) / range) * height;
      return `${x},${y}`;
    })
    .join(" ");

  const isPositive =
    firstValue !== undefined &&
    lastValue !== undefined &&
    lastValue >= firstValue;

  return (
    <svg
      className={styles.sparkline}
      width={width}
      height={height}
      viewBox={`0 0 ${width} ${height}`}
    >
      <polyline
        fill="none"
        stroke={isPositive ? "var(--text-success)" : "var(--text-error)"}
        strokeWidth="1.5"
        strokeLinecap="round"
        strokeLinejoin="round"
        points={points}
      />
    </svg>
  );
};

// Individual MetricCard component
const MetricCard = forwardRef<HTMLDivElement, MetricCardProps>(
  (
    { metric, variant = "default", loading = false, className, ...rest },
    ref,
  ) => {
    const {
      label,
      value,
      change,
      icon,
      sparkline,
      href,
      onClick,
      description,
      loading: itemLoading,
    } = metric;

    const isLoading = loading || itemLoading;
    const isInteractive = href || onClick;

    const classNames = [
      styles.card,
      styles[`variant-${variant}`],
      isInteractive && styles.interactive,
      isLoading && styles.loading,
      className,
    ]
      .filter(Boolean)
      .join(" ");

    const content = (
      <>
        <div className={styles.cardHeader}>
          {icon && <span className={styles.cardIcon}>{icon}</span>}
          <span className={styles.label}>{label}</span>
        </div>

        <div className={styles.cardBody}>
          {isLoading ? (
            <div className={styles.skeleton} />
          ) : (
            <>
              <span className={styles.value}>{value}</span>
              {sparkline && variant === "detailed" && (
                <Sparkline data={sparkline} />
              )}
            </>
          )}
        </div>

        {(change || description) && !isLoading && (
          <div className={styles.cardFooter}>
            {change && (
              <span
                className={`${styles.change} ${change.positive ? styles.positive : styles.negative}`}
              >
                {change.positive ? (
                  <TrendingUp size={12} />
                ) : (
                  <TrendingDown size={12} />
                )}
                <span>{change.value}</span>
                {change.label && (
                  <span className={styles.changeLabel}>{change.label}</span>
                )}
              </span>
            )}
            {description && variant === "detailed" && (
              <span className={styles.description}>{description}</span>
            )}
          </div>
        )}
      </>
    );

    if (href) {
      return (
        <a
          ref={ref as React.Ref<HTMLAnchorElement>}
          href={href}
          className={classNames}
          {...(rest as React.AnchorHTMLAttributes<HTMLAnchorElement>)}
        >
          {content}
        </a>
      );
    }

    if (onClick) {
      return (
        <button
          ref={ref as React.Ref<HTMLButtonElement>}
          type="button"
          onClick={onClick}
          className={classNames}
          {...(rest as React.ButtonHTMLAttributes<HTMLButtonElement>)}
        >
          {content}
        </button>
      );
    }

    return (
      <div ref={ref} className={classNames} {...rest}>
        {content}
      </div>
    );
  },
);

MetricCard.displayName = "MetricCard";

// Main MetricCards component
export const MetricCards = forwardRef<HTMLDivElement, MetricCardsProps>(
  (
    {
      metrics,
      columns = 4,
      variant = "default",
      loading = false,
      className,
      ...rest
    },
    ref,
  ) => {
    const classNames = [
      styles.metricCards,
      styles[`cols-${columns}`],
      className,
    ]
      .filter(Boolean)
      .join(" ");

    return (
      <div ref={ref} className={classNames} {...rest}>
        {metrics.map((metric, index) => (
          <MetricCard
            key={metric.id || metric.label || index}
            metric={metric}
            variant={variant}
            loading={loading}
          />
        ))}
      </div>
    );
  },
);

MetricCards.displayName = "MetricCards";

export { MetricCard };

/**
 * MetricCards Component Types
 *
 * Type definitions for the Orion MetricCards section component.
 * Designed for Product Mode (SaaS dashboards) KPI displays.
 */

import type { HTMLAttributes, ReactNode } from "react";

/**
 * Trend indicator for a metric
 */
export interface MetricTrend {
  /**
   * Trend value (e.g., "+12%", "-5%")
   */
  value: string;

  /**
   * Whether the trend is positive
   * @default true
   */
  positive?: boolean;

  /**
   * Comparison period label (e.g., "vs last month")
   */
  label?: string;
}

/**
 * Sparkline data point
 */
export type SparklineData = number[];

/**
 * Individual metric item
 */
export interface MetricItem {
  /**
   * Unique identifier
   */
  id?: string;

  /**
   * Metric label
   */
  label: string;

  /**
   * Main value (e.g., "$12,345", "89%", "1,234")
   */
  value: string | number;

  /**
   * Optional change/trend indicator
   */
  change?: MetricTrend;

  /**
   * Optional icon element
   */
  icon?: ReactNode;

  /**
   * Optional sparkline data
   */
  sparkline?: SparklineData;

  /**
   * Optional link to detailed view
   */
  href?: string;

  /**
   * Click handler (alternative to href)
   */
  onClick?: () => void;

  /**
   * Additional description
   */
  description?: string;

  /**
   * Loading state for this metric
   */
  loading?: boolean;
}

/**
 * MetricCards column count
 */
export type MetricCardsColumns = 2 | 3 | 4 | 5;

/**
 * MetricCards visual variant
 */
export type MetricCardsVariant = "default" | "compact" | "detailed";

/**
 * MetricCards section props
 *
 * @example
 * ```tsx
 * <MetricCards
 *   metrics={[
 *     { label: 'Revenue', value: '$12,345', change: { value: '+12%', positive: true } },
 *     { label: 'Users', value: '1,234', change: { value: '+5%', positive: true } },
 *     { label: 'Conversion', value: '3.2%', change: { value: '-0.5%', positive: false } }
 *   ]}
 *   columns={3}
 * />
 * ```
 */
export interface MetricCardsProps extends HTMLAttributes<HTMLDivElement> {
  /**
   * Array of metric items
   */
  metrics: MetricItem[];

  /**
   * Number of grid columns
   * @default 4
   */
  columns?: MetricCardsColumns;

  /**
   * Visual variant
   * - default: Standard cards with borders
   * - compact: Smaller padding and text
   * - detailed: Includes sparklines and descriptions
   * @default 'default'
   */
  variant?: MetricCardsVariant;

  /**
   * Loading state for all cards
   * @default false
   */
  loading?: boolean;
}

/**
 * Individual MetricCard props (internal component)
 */
export interface MetricCardProps extends HTMLAttributes<HTMLDivElement> {
  /**
   * Metric data
   */
  metric: MetricItem;

  /**
   * Visual variant
   */
  variant?: MetricCardsVariant;

  /**
   * Loading state
   */
  loading?: boolean;
}

/**
 * MetricCards Component Styles
 *
 * Optimized for Product Mode (SaaS dashboards).
 * Minimal shadows, no hover lift, compact typography.
 */

.metricCards {
  display: grid;
  gap: var(--mode-spacing-element);
}

.cols-2 {
  grid-template-columns: repeat(2, 1fr);
}

.cols-3 {
  grid-template-columns: repeat(3, 1fr);
}

.cols-4 {
  grid-template-columns: repeat(4, 1fr);
}

.cols-5 {
  grid-template-columns: repeat(5, 1fr);
}

/* ============================================================================
 * CARD STYLES
 * ============================================================================ */

.card {
  display: flex;
  flex-direction: column;
  gap: var(--spacing-2);
  padding: var(--mode-spacing-element);
  background: var(--surface-base);
  border: 1px solid var(--border-subtle);
  border-radius: var(--radius-control);
  text-decoration: none;
  color: inherit;
  box-shadow: var(--mode-shadow-default);
  transition:
    box-shadow var(--mode-hover-duration),
    border-color var(--mode-hover-duration);
}

.interactive {
  cursor: pointer;
}

.interactive:hover {
  border-color: var(--border-moderate);
  box-shadow: var(--mode-shadow-hover);
}

.interactive:focus-visible {
  outline: 2px solid var(--interactive-primary);
  outline-offset: 2px;
}

.loading {
  pointer-events: none;
}

/* ============================================================================
 * CARD HEADER
 * ============================================================================ */

.cardHeader {
  display: flex;
  align-items: center;
  gap: var(--spacing-2);
}

.cardIcon {
  display: flex;
  align-items: center;
  justify-content: center;
  width: 32px;
  height: 32px;
  background: var(--surface-subtle);
  border-radius: var(--radius-sm);
  color: var(--text-secondary);
}

.label {
  font-family: var(--font-secondary);
  font-size: var(--font-size-13);
  font-weight: var(--font-weight-medium);
  color: var(--text-secondary);
  line-height: var(--line-height-tight);
}

/* ============================================================================
 * CARD BODY
 * ============================================================================ */

.cardBody {
  display: flex;
  align-items: baseline;
  gap: var(--spacing-4);
  min-height: 36px;
}

.value {
  font-family: var(--font-secondary);
  font-size: clamp(1.5rem, 2vw, 1.75rem);
  font-weight: 600;
  color: var(--text-primary);
  line-height: 1;
  letter-spacing: -0.02em;
}

.skeleton {
  width: 100px;
  height: 32px;
  background: var(--surface-subtle);
  border-radius: var(--radius-sm);
  animation: pulse 1.5s ease-in-out infinite;
}

@keyframes pulse {
  0%,
  100% {
    opacity: 1;
  }
  50% {
    opacity: 0.5;
  }
}

.sparkline {
  flex-shrink: 0;
  opacity: 0.8;
}

/* ============================================================================
 * CARD FOOTER
 * ============================================================================ */

.cardFooter {
  display: flex;
  flex-direction: column;
  gap: var(--spacing-1);
  margin-top: var(--spacing-1);
}

.change {
  display: inline-flex;
  align-items: center;
  gap: var(--spacing-1);
  font-family: var(--font-secondary);
  font-size: var(--font-size-12);
  font-weight: var(--font-weight-medium);
}

.positive {
  color: var(--text-success);
}

.negative {
  color: var(--text-error);
}

.changeLabel {
  color: var(--text-tertiary);
  font-weight: var(--font-weight-normal);
  margin-left: var(--spacing-1);
}

.description {
  font-family: var(--font-secondary);
  font-size: var(--font-size-12);
  color: var(--text-tertiary);
  line-height: var(--line-height-relaxed);
}

/* ============================================================================
 * VARIANT: COMPACT
 * ============================================================================ */

.variant-compact {
  padding: var(--spacing-3);
  gap: var(--spacing-1);
}

.variant-compact .cardIcon {
  width: 24px;
  height: 24px;
}

.variant-compact .label {
  font-size: var(--font-size-12);
}

.variant-compact .cardBody {
  min-height: 28px;
}

.variant-compact .value {
  font-size: var(--font-size-20);
}

.variant-compact .change {
  font-size: var(--font-size-11);
}

/* ============================================================================
 * VARIANT: DETAILED
 * ============================================================================ */

.variant-detailed {
  padding: var(--spacing-5);
  gap: var(--spacing-3);
}

.variant-detailed .cardIcon {
  width: 40px;
  height: 40px;
}

.variant-detailed .cardBody {
  justify-content: space-between;
}

.variant-detailed .value {
  font-size: var(--font-size-32);
}

/* ============================================================================
 * RESPONSIVE
 * ============================================================================ */

@media (max-width: 1200px) {
  .cols-5 {
    grid-template-columns: repeat(3, 1fr);
  }

  .cols-4 {
    grid-template-columns: repeat(2, 1fr);
  }
}

@media (max-width: 768px) {
  .cols-5,
  .cols-4,
  .cols-3 {
    grid-template-columns: repeat(2, 1fr);
  }
}

@media (max-width: 480px) {
  .cols-5,
  .cols-4,
  .cols-3,
  .cols-2 {
    grid-template-columns: 1fr;
  }

  .card {
    padding: var(--spacing-4);
  }
}

export { MetricCards, MetricCard } from "./MetricCards";
export type {
  MetricCardsProps,
  MetricCardProps,
  MetricItem,
  MetricTrend,
  SparklineData,
  MetricCardsColumns,
  MetricCardsVariant,
} from "./MetricCards.types";
